#!/usr/bin/env python3
import base64
from pathlib import Path

root = Path.cwd()
public_dir = root / 'frontend/public'
index_path = public_dir / 'index.html'
manifest_path = public_dir / 'manifest.json'
doc_path = root / 'docs/FLIGHTLINE-MOBILE-THEME-LAYOUT-PHASE-7B-2026-06-26.md'

public_dir.mkdir(parents=True, exist_ok=True)

icons = {
    'apple-touch-icon.png': '''''',
    'icon-192.png': '''''',
}

for filename, data in icons.items():
    (public_dir / filename).write_bytes(base64.b64decode(data))

manifest = '''{
  "short_name": "FlightLine",
  "name": "FlightLine Command Center",
  "description": "Mobile command for dealership deal flow",
  "start_url": ".",
  "display": "standalone",
  "orientation": "portrait",
  "background_color": "#0F172A",
  "theme_color": "#0F172A",
  "icons": [
    {
      "src": "icon-192.png",
      "sizes": "192x192",
      "type": "image/png",
      "purpose": "any maskable"
    }
  ]
}
'''
manifest_path.write_text(manifest)

if not index_path.exists():
    raise SystemExit('Missing frontend/public/index.html')

index = index_path.read_text()

index = index.replace(
    '<link rel="icon" href="%PUBLIC_URL%/favicon.ico" />',
    '<link rel="icon" href="%PUBLIC_URL%/icon-192.png" />'
)

anchor = '    <meta name="viewport" content="width=device-width, initial-scale=1" />'
head_inserts = [
    '<link rel="apple-touch-icon" href="%PUBLIC_URL%/apple-touch-icon.png" />',
    '<link rel="manifest" href="%PUBLIC_URL%/manifest.json" />',
    '<meta name="apple-mobile-web-app-capable" content="yes" />',
    '<meta name="apple-mobile-web-app-status-bar-style" content="black-translucent" />',
    '<meta name="apple-mobile-web-app-title" content="FlightLine" />'
]

for line in reversed(head_inserts):
    if line not in index:
        index = index.replace(anchor, f'    {line}\n{anchor}')

index = index.replace(
    'content="Flightline - Dealership Command Center"',
    'content="FlightLine - Dealership Deal-Flow Command Center"'
)
index = index.replace(
    '<title>Flightline - Command Center</title>',
    '<title>FlightLine - Command Center</title>'
)

index_path.write_text(index)

if doc_path.exists():
    doc = doc_path.read_text()
    if 'frontend/public/apple-touch-icon.png' not in doc:
        doc = doc.replace(
            'frontend/public/flightline-logo.svg\n```',
            'frontend/public/flightline-logo.svg\nfrontend/public/apple-touch-icon.png\nfrontend/public/icon-192.png\nfrontend/public/manifest.json\nfrontend/public/index.html\n```'
        )
    if 'PWA home-screen icon wired for iPhone and manifest support.' not in doc:
        doc = doc.replace(
            '- FL logo added to the mobile header.',
            '- FL logo added to the mobile header.\n- PWA home-screen icon wired for iPhone and manifest support.'
        )
    doc_path.write_text(doc)

print('Applied FlightLine PWA icon patch.')
print('Wrote frontend/public/apple-touch-icon.png')
print('Wrote frontend/public/icon-192.png')
print('Wrote frontend/public/manifest.json')
print('Updated frontend/public/index.html')
print('Updated Phase 7B documentation if present')
